#include<iostream>#include<algorithm>#include<vector>#include<climits>#define ll long longusing namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        vector<pair<ll,ll>> b(n);        for(int i=0;i<n;i++){            cin>>a[i];            b[i]={a[i],i};        }        sort(b.begin(),b.end());        vector<ll> ans(n);                vector<ll> prefix_sum(n);        prefix_sum[0]= b[0].first;        for(int i=1;i<n;i++){            prefix_sum[i]= prefix_sum[i-1]+b[i].first;        }        for(int i=0;i<n;i++){            ll j=i;            ll curr_ele=i;            while(j<n){                pair<ll,ll>curr_pair= {prefix_sum[j] + 1, INT_MIN};                ll idx= lower_bound(b.begin(),b.end(),curr_pair)-b.begin();                idx--;                if(idx==j)break;                curr_ele+= (idx-j);                j=idx;            }            ans[b[i].second]= curr_ele;        }         for(int i=0;i<n;i++){            cout<<ans[i]<<" ";        }        cout<<"\n";    }}